    26→@Injectable()
    27→export class RelatedProductsService {
    28→	private readonly logger = new Logger(RelatedProductsService.name);
    29→
    30→	constructor(
    31→		private readonly algoliaService: AlgoliaService,
    32→		private readonly mmsService: MmsService,
    33→		private readonly metricsService: MetricsService,
    34→		private readonly productHydrationService: ProductHydrationService,
    35→		private readonly styleColorsService: StyleColorsService,
    36→		private readonly stylesService: StylesService,
    37→	) {}
    38→
    39→	private async getCurrentColorStyle(
    40→		styleId: number,
    41→		colorId?: number,
    42→	): Promise<IStyleColorBase | null> {
    43→		if (colorId) {
    44→			const styleByColor = await this.styleColorsService.getStyleByStyleAndColorId({
    45→				styleId,
    46→				colorId,
    47→			});
    48→			if (styleByColor) {
    49→				return styleByColor;
    50→			}
    51→		}
    52→
    53→		const style = await this.styleColorsService.getStyleByStyleId({ styleId });
    54→		if (!style) {
    55→			this.logger.warn(`No style found for productId ${styleId}.`);
    56→		}
    57→		return style;
    58→	}
    59→
    60→	async getRelatedProducts(
    61→		productId: string,
    62→		query: RelatedProductsQueryDto,
    63→	): Promise<RelatedProductsResponseDto> {
    64→		if (!productId || productId.trim() === '') {
    65→			this.logger.error('Product ID is required to fetch related products');
    66→			throw new BadRequestException('Product ID is required');
    67→		}
    68→
    69→		this.logger.log(
    70→			`[getRelatedProducts]: Fetching related products for productId: ${productId}, colorId: ${query.colorId}, limit: ${query.limit}`,
    71→		);
    72→		const { limit, colorId } = query;
    73→
    74→		try {
    75→			const styleIds = await this.algoliaService.getRelatedProductIds({
    76→				productId: Number(productId),
    77→			});
    78→
    79→			if (styleIds.length === 0) {
    80→				throw new NotFoundException(
    81→					`No related products found for product ID: ${productId}`,
    82→				);
    83→			}
    84→
    85→			const currentStyleColor = await this.getCurrentColorStyle(
    86→				Number(productId),
    87→				colorId,
    88→			);
    89→
    90→			const relatedProducts = await this.productHydrationService.hydrateProducts({
    91→				styleIds,
    92→				currentStyleColor,
    93→			});
    94→
    95→			if (relatedProducts.length === 0) {
    96→				throw new NotFoundException(
    97→					`No related products found for product ID: ${productId}`,
    98→				);
    99→			}
   100→
   101→			return {
   102→				product_id: productId,
   103→				related_products: relatedProducts.slice(0, limit),
   104→				color_id: colorId ?? null,
   105→			};
   106→		} catch (error: unknown) {
   107→			const err = error instanceof Error ? error : new Error(String(error));
   108→			this.logger.error(
   109→				`Error fetching related products from Algolia for productId ${productId}: ${err.message}`,
   110→				err.stack,
   111→			);
   112→
   113→			await this.metricsService.incrementDailyCounter(dailyTrackingKeys.MMS_REQUESTS);
   114→
   115→			const { alternatives } = await this.mmsService.getRelatedProducts(
   116→				productId,
   117→				colorId,
   118→			);
   119→
   120→			if (alternatives.length === 0) {
   121→				this.logger.warn(
   122→					`No MMS alternatives products found for product ID: ${productId}`,
   123→				);
   124→			}
   125→
   126→			return {
   127→				product_id: productId,
   128→				related_products: alternatives,
   129→				mms_fallback: true,
   130→				color_id: colorId ?? null,
   131→			};
   132→		}
   133→	}
   134→
   135→	async getBrandProducts(
   136→		query: BrandProductsQueryDto,
   137→	): Promise<BrandProductsResponseDto> {
   138→		const { brand, limit, colorId, styleId, sortBy } = query;
   139→		try {
   140→			const { products, mvRecords } =
   141→				await this.productHydrationService.getProductsByBrands({
   142→					brands: [brand],
   143→					limit: 1000,
   144→				});
   145→
   146→			if (products.length === 0) {
   147→				throw new NotFoundException(`No products found for brand: ${brand}`);
   148→			}
   149→
   150→			let currentStyleColor: IStyleColorBase | null = null;
   151→			if (colorId && styleId) {
   152→				currentStyleColor = await this.styleColorsService.getStyleByStyleAndColorId({
   153→					styleId: Number(styleId),
   154→					colorId: Number(colorId),
   155→				});
   156→			}
   157→
   158→			const productsWithColor = currentStyleColor
   159→				? (() => {
   160→						const colorCache = new Map<
   161→							number,
   162→							ReturnType<
   163→								typeof this.productHydrationService.convertMvColorsToProductColors
   164→							>
   165→						>();
   166→						return products.map((product) => {
   167→							const mv = mvRecords.get(product.style_id);
   168→							let colors = colorCache.get(product.style_id);
   169→							if (!colors) {
   170→								colors = this.productHydrationService.convertMvColorsToProductColors(
   171→									mv?.colors ?? null,
   172→								);
   173→								colorCache.set(product.style_id, colors);
   174→							}
   175→							if (colors.length > 0 && currentStyleColor) {
   176→								const closestColorId = findClosestColorId(currentStyleColor, colors);
   177→								const closestColor = colors.find((c) => c.id === closestColorId);
   178→								if (closestColor) {
   179→									return {
   180→										...product,
   181→										color: closestColorId,
   182→										image_src: closestColor.image_url ?? product.image_src,
   183→									};
   184→								}
   185→							}
   186→							return product;
   187→						});
   188→					})()
   189→				: products;
   190→
   191→			let finalProducts = productsWithColor;
   192→
   193→			if (sortBy) {
   194→				let currentStyleCategoryId: number | null = null;
   195→				if (sortBy === 'category' && styleId) {
   196→					const currentStyle = await this.stylesService.getStyleById({
   197→						styleId: Number(styleId),
   198→					});
   199→					currentStyleCategoryId = currentStyle?.primary_category_id ?? null;
   200→				}
   201→				finalProducts = sortStyles({
   202→					products: productsWithColor,
   203→					sortBy,
   204→					currentStyleCategoryId,
   205→				});
   206→			}
   207→
   208→			return {
   209→				product_id: styleId?.toString() ?? '',
   210→				brand_products: finalProducts.slice(0, limit),
   211→				color_id: colorId ?? null,
   212→				brand,
   213→				sort_by: sortBy ?? null,
   214→			};
   215→		} catch (error: unknown) {
   216→			const err = error instanceof Error ? error : new Error(String(error));
   217→			this.logger.error(
   218→				`Failed to get products for brand ${query.brand}: ${err.message}`,
   219→				err.stack,
   220→			);
   221→
   222→			throw err;
   223→		}
   224→	}
   225→}
