    11→@Injectable()
    12→export class MetricsService {
    13→	constructor(private readonly cacheService: CacheService) {}
    14→
    15→	@LogExecution({
    16→		paramFormatter: (params) => params,
    17→		responseFormatter: () => '',
    18→	})
    19→	async incrementDailyCounter(metricType: dailyTrackingKeys): Promise<void> {
    20→		const today = new Date().toISOString().split('T')[0];
    21→		const key = `${metricType}:${today}`;
    22→
    23→		await this.cacheService.incrementByOne({ namespace: Namespaces.METRICS, key });
    24→	}
    25→}
