    98→	private mapRecordsToProductsWithMvMap(
    99→		records: IStylesMvBase[],
   100→		currentStyleColor: IStyleColorBase | null,
   101→	): { products: IRelatedProduct[]; mvRecords: Map<number, IStylesMvBase> } {
   102→		const mvRecordsMap = new Map<number, IStylesMvBase>();
   103→		const products: IRelatedProduct[] = [];
   104→
   105→		for (const record of records) {
   106→			mvRecordsMap.set(record.style_id, record);
   107→			products.push(this.mapStyleMvToRelatedProduct(record, currentStyleColor));
   108→		}
   109→
   110→		return { products, mvRecords: mvRecordsMap };
   111→	}
