   113→	mapStyleMvToRelatedProduct(
   114→		style: IStylesMvBase,
   115→		currentStyleColor: IStyleColorBase | null,
   116→	): IRelatedProduct {
   117→		const colors = style.colors ?? [];
   118→		const colorsAsProductColors = this.convertMvColorsToProductColors(colors);
   119→
   120→		const closestColorId = currentStyleColor
   121→			? findClosestColorId(currentStyleColor, colorsAsProductColors)
   122→			: (colors[0]?.id ?? 0);
   123→
   124→		const closestColor = colors.find((color) => color.id === closestColorId) ?? colors[0];
   125→
   126→		const sizing = formatSizes(style.sizes ?? []);
   127→
   128→		return {
   129→			color: closestColor?.id ?? 0,
   130→			link: style.link ?? '',
   131→			sizing,
   132→			sizes: style.sizes ?? [],
   133→			min_qty: style.no_minimum ? 1 : (style.min_qty ?? style.minimum_quantity ?? 0),
   134→			complement_badge: null,
   135→			rating_score: String(style.rating_score ?? ''),
   136→			rating_count: String(style.rating_count ?? ''),
   137→			name: String(style.name ?? ''),
   138→			style_id: style.style_id,
   139→			decoration_method: String(style.decoration_method ?? ''),
   140→			primary_category_id: style.primary_category_id,
   141→			primary_category_name: String(style.primary_category_name ?? ''),
   142→			default_quote_qty: style.default_quote_qty ?? 1,
   143→			style_type: style.style_type ?? '',
   144→			image_src:
   145→				(String(closestColor?.image_url ?? '') || style.style_card_image_url) ?? '',
   146→			broad_category_names: style.broad_category_names ?? [],
   147→			sub_category_names: style.sub_category_names ?? [],
   148→			turn_time: style.turn_time ?? 0,
   149→			rush_turn_time: style.rush_turn_time ?? 0,
   150→			default_unit_prices: (style.default_unit_prices ?? []).map((p) => ({
   151→				algorithm: p.algorithm ?? '',
   152→				quantity: p.quantity,
   153→				price: p.price,
   154→				regular_unit_price: p.regular_unit_price ?? null,
   155→			})),
   156→			brand: style.brand ?? [],
   157→		};
   158→	}
   159→
   160→	convertMvColorsToProductColors(colors: IStylesMvColor[] | null): IProductColor[] {
   161→		if (!colors) {
   162→			return [];
   163→		}
   164→		return colors.map((color) => {
   165→			const productColor: IProductColor = {
   166→				id: color.id,
   167→				name: color.name,
   168→				rbgs: color.rbgs ?? [],
   169→			};
   170→			if (color.image_url !== null) {
   171→				productColor.image_url = color.image_url;
   172→			}
   173→			return productColor;
   174→		});
   175→	}
   176→}
