    71→	async getRelatedProducts(
    72→		productId: string,
    73→		colorId?: number,
    74→	): Promise<IMMSRelatedProductsResponse> {
    75→		try {
    76→			const cacheKey = this.generateRelatedProductKey(productId, colorId);
    77→
    78→			const cachedMMSData = await this.cacheService.get<IRelatedProduct[]>({
    79→				namespace: Namespaces.MMS_ALTERNATIVES,
    80→				key: cacheKey,
    81→			});
    82→
    83→			if (cachedMMSData) {
    84→				this.logger.log(`Returning cached MMS data for productId: ${productId}`);
    85→				return {
    86→					alternatives: cachedMMSData,
    87→				};
    88→			}
    89→
    90→			const mmsUrl = `${this.ciBaseUrl}/products/styles/${productId}/related_styles.json?PK=${colorId ?? productId}`;
    91→
    92→			this.logger.log(`Fetching related products from MMS for productId: ${productId}`);
    93→
    94→			const response = await fetch(mmsUrl, {
    95→				signal: AbortSignal.timeout(REQUEST_TIMEOUT_MS),
    96→			});
    97→
    98→			if (!response.ok) {
    99→				this.logger.error(
   100→					`Error fetching related products from MMS for productId ${productId} and colorId ${colorId}: ${response.statusText}`,
   101→				);
   102→				throw new Error(
   103→					`Failed to fetch related products from MMS for productId ${productId} and colorId ${colorId}`,
   104→				);
   105→			}
   106→
   107→			// MMS can return HTML page if no related styles found
   108→			if (!response.headers.get('content-type')?.includes('application/json')) {
   109→				throw new HttpException(
   110→					`No related styles found in MMS response for productId: ${productId} and colorId ${colorId}`,
   111→					HttpStatus.NOT_FOUND,
   112→				);
   113→			}
   114→
   115→			const data = (await response.json()) as IMMSRelatedProductsPayload;
   116→			const { alternatives } = data;
   117→			const mappedAlternatives = this.mapMmsResponseToRelatedProducts(alternatives);
   118→
   119→			await this.cacheService.set({
   120→				namespace: Namespaces.MMS_ALTERNATIVES,
   121→				key: cacheKey,
   122→				value: mappedAlternatives,
   123→				ttl: this.relatedProductsCacheTtl,
   124→			});
   125→
   126→			return {
   127→				alternatives: mappedAlternatives,
   128→			};
   129→		} catch (error: unknown) {
   130→			const err = error instanceof Error ? error : new Error(String(error));
   131→
   132→			if (err.name === 'TimeoutError') {
   133→				this.logger.warn(
   134→					`Request timeout for productId ${productId} and colorId ${colorId}`,
   135→				);
   136→				throw new HttpException(
   137→					`Request timeout for productId ${productId} and colorId ${colorId}`,
   138→					HttpStatus.NOT_FOUND,
   139→				);
   140→			}
   141→
   142→			this.logger.error(
   143→				`Error in MMS service for productId ${productId} and colorId ${colorId}: ${err.message}`,
   144→				err.stack,
   145→			);
   146→			rollbar.error(err);
   147→			throw err;
   148→		}
   149→	}
