   259→	async makeRequest<T>(endpoint: string, options?: RequestInit): Promise<T> {
   260→		try {
   261→			const url = endpoint.startsWith('http')
   262→				? endpoint
   263→				: `${this.mmsApiUrlHost}${endpoint}`;
   264→			this.logger.debug(`Making MMS request to: ${url}`);
   265→
   266→			const response = await fetch(url, options);
   267→
   268→			if (!response.ok) {
   269→				this.logger.error(
   270→					`MMS request failed: ${response.status} ${response.statusText} for ${url}`,
   271→				);
   272→				throw new Error(`MMS request failed: ${response.statusText}`);
   273→			}
   274→
   275→			const data = (await response.json()) as T;
   276→			this.logger.debug(`MMS request successful for: ${url}`);
   277→			return data;
   278→		} catch (error: unknown) {
   279→			const err = error instanceof Error ? error : new Error(String(error));
   280→			this.logger.error(
   281→				`Error making MMS request to ${endpoint}: ${err.message}`,
   282→				err.stack,
   283→			);
   284→			rollbar.error(err);
   285→			throw err;
   286→		}
   287→	}
